const contacts = [
  { name: 'Sarah Chen', role: 'VP Product, Fintech.io', relationship: 'peer', last_contact: '2026-04-10', outreach_cadence_days: 60, context: 'Met at ProductCon 2025. Gave great advice on pricing strategy for SMB. Wants to hear how Q3 launch goes.', current_news: 'Fintech.io just raised Series B — congrats moment', priority: 'high' },
  { name: 'Marcus Obi', role: 'Founder, CreatorOS', relationship: 'investor_adjacent', last_contact: '2026-05-20', outreach_cadence_days: 45, context: 'Angel in our pre-seed round. Very well-networked. Offered to intro to 3 enterprise buyers.', current_news: null, priority: 'high' },
  { name: 'Priya Nair', role: 'Engineering Manager, Stripe', relationship: 'technical_advisor', last_contact: '2026-06-01', outreach_cadence_days: 90, context: 'Helped us debug our Stripe integration. Has deep expertise in payment reliability. Offered to review our architecture doc.', current_news: null, priority: 'medium' },
  { name: 'James Walton', role: 'CEO, TaskFlow (competitor)', relationship: 'competitor_friendly', last_contact: '2026-01-15', outreach_cadence_days: 90, context: 'Met at SaaStr. Surprisingly open conversation about the market. Said he\"d swap NPS insights.', current_news: 'TaskFlow launched Gantt view last week', priority: 'low' }
];
const today = '2026-07-14';
return [{ json: { contacts, today, my_context: { name: 'Jamie', company: 'ProjectFlow', recent_win: 'Shipped recurring tasks feature, targeting July 31 GA', looking_for: 'enterprise buyer introductions, hiring advice for first FE lead role' } } }];

const { contacts, today, my_context } = $input.first().json;
const todayMs = new Date(today).getTime();
const prioritised = contacts.map(c => {
  const lastMs = new Date(c.last_contact).getTime();
  const days_since = Math.floor((todayMs - lastMs)/(1000*60*60*24));
  const overdue = days_since >= c.outreach_cadence_days;
  const urgency_score = (days_since / c.outreach_cadence_days) * (c.priority === 'high' ? 2 : c.priority === 'medium' ? 1.5 : 1);
  return { ...c, days_since_contact: days_since, overdue, urgency_score: parseFloat(urgency_score.toFixed(2)) };
}).sort((a,b) => b.urgency_score - a.urgency_score);
const to_contact = prioritised.filter(c => c.overdue);
const contactsText = to_contact.map(c => `  ${c.name} (${c.role}) — ${c.days_since_contact}d since last contact (target ${c.outreach_cadence_days}d)
  Context: ${c.context}${c.current_news ? '
  News peg: '+c.current_news : ''}`).join('

');
const system = `You are a relationship-focused founder coach. You help founders maintain their network without feeling transactional. You draft brief, warm, personalised outreach messages that feel human — not automated. Reference specific context about the relationship. Return ONLY valid JSON.`;
const user = `I am ${my_context.name}, founder of ${my_context.company}. Recent update: ${my_context.recent_win}. Currently looking for: ${my_context.looking_for}.

These contacts are overdue for outreach:
${contactsText}

For each contact, draft a short (3–5 sentence) outreach message. Return JSON:
{
  "outreach_list": [
    {
      "name": "string",
      "channel": "LinkedIn|Email|Twitter",
      "draft_message": "string",
      "ask_or_offer": "string — what I'm giving or asking for in this outreach",
      "why_now": "string"
    }
  ],
  "skip_list": [{ "name": "string", "reason": "string" }],
  "weekly_networking_goal": "string — what success looks like for networking this week"
}`;
return [{ json: { contacts: prioritised, to_contact, my_context, today, system_prompt: system, user_prompt: user } }];

const response = $input.first().json;
const upstream = $('Prioritise & Prepare Drafts').first().json;
let parsed;
try {
  const c = response.choices?.[0]?.message?.content;
  if (!c) throw new Error('No content');
  parsed = JSON.parse(c);
} catch(e) { return [{ json: { _error: true, reason: e.message } }]; }
if (!parsed.outreach_list || !Array.isArray(parsed.outreach_list)) return [{ json: { _error: true, reason: 'Missing outreach_list' } }];
return [{ json: { _error: false, outreach: parsed, ctx: upstream, meta: { outreach_count: parsed.outreach_list.length, today: upstream.today, generated_at: new Date().toISOString() } } }];

const { outreach: o, ctx, meta: m } = $input.first().json;
const outreachLines = o.outreach_list.map(item => [
  `  [${item.channel}] ${item.name}`,
  `  Why now: ${item.why_now}`,
  `  Ask/offer: ${item.ask_or_offer}`,
  `  Draft:`,
  `  "${item.draft_message}"`,
  ''
].join('\n')).join('\n');
const skipLines = (o.skip_list||[]).map(s => `  ${s.name}: ${s.reason}`).join('\n');
const report = [
  `NETWORK NURTURER: Week of ${m.today}`,
  `Generated: ${m.generated_at} | Outreach: ${m.outreach_count} contacts`,
  ``,
  `WEEKLY GOAL: ${o.weekly_networking_goal}`,
  ``,
  `OUTREACH DRAFTS (APPROVAL REQUIRED — review and personalise before sending):`,
  outreachLines,
  skipLines ? `SKIPPED:\n${skipLines}` : ''
].filter(Boolean).join('\n');
return [{ json: { ...($input.first().json), report_text: report } }];
